import {
  Badge,
  Container,
  Meter,
  Separator,
  Statistic,
} from "@gunjo/ui";
import { DayServiceBoard } from "./DayServiceBoard";
import { capacity, officeName, todayLabel, users } from "./data";

export const metadata = {
  title: "デイサービス 当日運営管理 | デイサービスセンター 陽だまりの家",
  description:
    "通所介護（デイサービス）の生活相談員・管理者向け 当日運営管理画面。本日の利用者・送迎・入浴・機能訓練・加算・ケア記録の署名をひと目で。",
};

export default function DayServicePage() {
  // ── サマリ集計（サーバー側で計算：data.ts は関数を持たないので安全）──
  const active = users.filter((u) => u.status !== "欠席");
  const present = users.filter((u) => u.status === "在所").length;
  const notArrived = users.filter((u) => u.status === "未到着").length;
  const absent = users.filter((u) => u.status === "欠席").length;
  const bathPlanned = active.filter((u) => u.bath === "予定" || u.bath === "実施").length;
  const occupancyRate = Math.round((active.length / capacity) * 100);

  return (
    <Container size="xl" as="main" className="py-6">
      {/* ── ヘッダ ── */}
      <header className="mb-6 flex flex-col gap-1">
        <div className="flex flex-wrap items-center gap-2">
          <h1 className="text-xl font-bold tracking-tight sm:text-2xl">
            当日運営管理
          </h1>
          <Badge variant="info">通所介護（デイサービス）</Badge>
        </div>
        <p className="text-sm text-muted-foreground">
          {officeName}・{todayLabel}・提供時間区分 7-8時間 中心
        </p>
      </header>

      {/* ── サマリ メトリクス ── */}
      <section aria-label="本日のサマリ" className="mb-6 flex flex-col gap-4">
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-6">
          <Statistic label="本日の利用者" value={`${active.length}名`} hint={`定員 ${capacity}名`} />
          <Statistic
            label="稼働率"
            value={`${occupancyRate}%`}
            trend={occupancyRate >= 85 ? "up" : "flat"}
            tone={occupancyRate >= 85 ? "positive" : "neutral"}
            hint="対 定員"
          />
          <Statistic label="在所" value={`${present}名`} tone="positive" />
          <Statistic
            label="未到着"
            value={`${notArrived}名`}
            tone={notArrived > 0 ? "negative" : "neutral"}
            hint="送迎到着待ち"
          />
          <Statistic label="入浴予定" value={`${bathPlanned}名`} hint="入浴介助加算 対象" />
          <Statistic
            label="欠席"
            value={`${absent}名`}
            tone={absent > 0 ? "negative" : "neutral"}
            hint="当日キャンセル含む"
          />
        </div>

        {/* 稼働率メーター（定員に対する稼働） */}
        <div className="rounded-lg border border-border bg-card p-4">
          <Meter
            label={`稼働状況（利用 ${active.length}名 / 定員 ${capacity}名）`}
            value={active.length}
            max={capacity}
            direction="higher-is-better"
            target={Math.round(capacity * 0.85)}
            formatValue={(n) => `${Math.round(n)}名`}
          />
          <p className="mt-2 text-xs text-muted-foreground">
            マーカーは目標稼働（定員の85%＝{Math.round(capacity * 0.85)}名）です。
          </p>
        </div>
      </section>

      <Separator className="mb-6" />

      {/* ── 当日運営ボード（クライアント：タブ・送迎・記録署名・ドリルイン）── */}
      <DayServiceBoard />
    </Container>
  );
}

