function careLevelTone(level: string): "info" | "warning" | "destructive" | "secondary" {
  if (level.startsWith("要支援")) return "secondary";
  if (level === "要介護1" || level === "要介護2") return "info";
  if (level === "要介護3") return "warning";
  return "destructive"; // 要介護4-5
}

const CARE_STATE_TONE: Record<CareState, "success" | "info" | "destructive" | "secondary" | "warning"> = {
  実施: "success",
  予定: "info",
  拒否: "destructive",
  未実施: "warning",
  対象外: "secondary",
};

const STATUS_TONE: Record<DayUser["status"], "success" | "info" | "warning" | "destructive" | "secondary"> = {
  在所: "success",
  送迎中: "info",
  未到着: "warning",
  帰宅済: "secondary",
  欠席: "destructive",
};

/** バイタル異常があれば true */
function hasAbnormalVital(u: DayUser): boolean {
  const r = u.record;
  if (r.temp === undefined && r.systolic === undefined) return false;
  const t = r.temp !== undefined ? flagValue(r.temp, vitalRanges.temp) !== "normal" : false;
  const s = r.systolic !== undefined ? flagValue(r.systolic, vitalRanges.systolic) !== "normal" : false;
  const o = r.spo2 !== undefined ? flagValue(r.spo2, vitalRanges.spo2) !== "normal" : false;
  const p = r.pulse !== undefined ? flagValue(r.pulse, vitalRanges.pulse) !== "normal" : false;
  return t || s || o || p;
}

function fmtTime(iso: string): string {
  const m = /T(\d{2}):(\d{2})/.exec(iso);
  return m ? `${m[1]}:${m[2]}` : iso;
}

// 「アバター + 利用者名 + 属性 + ステータス」セル — PersonCell に集約
function UserCell({
  u,
  size = "md",
  onClick,
}: {
  u: DayUser;
  size?: "sm" | "md" | "lg";
  onClick?: () => void;
}) {
  const cell = (
    <PersonCell
      name={u.name}
      secondary={`${u.kana}・${u.age}歳${u.sex}`}
      tertiary={`${u.careLevel}／${u.serviceBand}`}
      size={size}
      avatarClassName={u.avatarColor}
      trailing={<Badge variant={STATUS_TONE[u.status]}>{u.status}</Badge>}
    />
  );
  if (!onClick) return cell;
  return (
    <button
      type="button"
      onClick={onClick}
      className="w-full rounded-lg px-2 py-1.5 text-left transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
      aria-label={`${u.name} の本日のケア記録を開く`}
    >
      {cell}
    </button>
  );
}

// ── 送迎ルート → RouteStops 形式へ ──
function stopStatus(s: RouteStop): RouteStopStatus {
  if (s.failed) return "failed";
  if (s.done) return "completed";
  return "pending";
}

function buildRouteItems(
  route: Route,
  stops: RouteStop[],
  byId: Record<string, DayUser>,
  onToggle: (routeId: string, userId: string) => void
): RouteStopItem[] {
  return stops.map((s) => {
    const u = byId[s.userId];
    const status = stopStatus(s);
    return {
      id: `${route.id}-${s.userId}`,
      seq: s.seq,
      title: u ? `${u.name}（${u.careLevel}）` : s.userId,
      description: u?.note,
      status,
      plannedTime: s.planned,
      actualTime: s.actual,
      actions:
        route.kind === "pickup" && !s.failed ? (
          <Button
            size="sm"
            variant={s.done ? "outline" : "default"}
            onClick={() => onToggle(route.id, s.userId)}
          >
            {s.done ? "乗車取消" : "乗車にする"}
          </Button>
        ) : s.failed ? (
          <Badge variant="destructive" icon={<IconAlertTriangle />}>
            要連絡（不在）
          </Badge>
        ) : undefined,
    };
  });
}

export function DayServiceBoard() {
  // 状態：利用者（ケア記録・ステータスを更新可能に）
