  const [stops, setStops] = React.useState<Record<string, RouteStop[]>>(routeStops);
  const [openId, setOpenId] = React.useState<string | null>(null);
  const [showAbsent, setShowAbsent] = React.useState(true);

  const byId = React.useMemo(
    () => Object.fromEntries(users.map((u) => [u.id, u])) as Record<string, DayUser>,
    [users]
  );

  // ── 集計（稼働・加算・送迎）──
  const active = users.filter((u) => u.status !== "欠席");
  const bathPlanned = active.filter((u) => u.bath === "予定" || u.bath === "実施").length;
  const bathDone = active.filter((u) => u.bath === "実施").length;
  const exerciseDone = active.filter((u) => u.exercise === "実施").length;

  const additionCounts = {
    bath: bathDone,
    exercise: exerciseDone,
  };

  // 未到着（迎えが未完了）の利用者 — トップに警告で出す
  const stillWaiting = users.filter((u) => u.status === "未到着" && u.pickupRouteId);

  // ── アクション ──
  const toggleRideStop = (routeId: string, userId: string) => {
    setStops((prev) => {
      const list = prev[routeId] ?? [];
      const next = list.map((s) =>
        s.userId === userId
          ? { ...s, done: !s.done, actual: !s.done ? fmtNow() : undefined }
          : s
      );
      return { ...prev, [routeId]: next };
    });
    // 迎え便で乗車にしたら、利用者ステータスを 在所 に
    const route = routes.find((r) => r.id === routeId);
    if (route?.kind === "pickup") {
      setUsers((prev) =>
        prev.map((u) => {
          if (u.id !== userId) return u;
          const wasDone = (stops[routeId] ?? []).find((s) => s.userId === userId)?.done;
          return { ...u, status: wasDone ? "未到着" : "在所" };
        })
      );
    }
  };

  const setRecordSigned = (userId: string, value: SignedRecordValue) => {
    setUsers((prev) =>
      prev.map((u) =>
        u.id === userId
          ? {
              ...u,
              record: {
                ...u.record,
                signed: value.status === "signed",
                signedBy: value.signedBy ?? u.record.signedBy,
                signedAt: value.signedAt ?? u.record.signedAt,
              },
            }
          : u
      )
    );
  };

  const setBathResult = (userId: string, result: CareState) => {
    setUsers((prev) =>
      prev.map((u) => (u.id === userId ? { ...u, bath: result } : u))
    );
  };

  const openUser = openId ? byId[openId] : null;

  return (
    <div className="flex flex-col gap-6">
      {/* 未到着アラート（送迎の取りこぼし防止） */}
      {stillWaiting.length > 0 ? (
        <Card className="border-warning-border bg-warning-subtle">
          <CardContent className="flex flex-wrap items-center gap-x-3 gap-y-2 p-4">
            <IconBus className="h-5 w-5 shrink-0 text-warning" aria-hidden="true" />
            <p className="text-sm font-medium text-warning-subtle-foreground">
              未到着 {stillWaiting.length} 名：
              {stillWaiting.map((u) => u.name).join("・")}（送迎の到着待ち）
            </p>
          </CardContent>
        </Card>
      ) : null}

      <Tabs defaultValue="roster">
        <TabsList className="w-full">
          <TabsTrigger value="roster">本日の利用者</TabsTrigger>
          <TabsTrigger value="transport">送迎管理</TabsTrigger>
          <TabsTrigger value="schedule">入浴・訓練</TabsTrigger>
          <TabsTrigger value="additions">加算・担当</TabsTrigger>
        </TabsList>

        {/* ─────────── 本日の利用者一覧 ─────────── */}
        <TabsContent value="roster">
          <div className="flex flex-col gap-4">
            <div className="flex items-center justify-between gap-3">
              <h2 className="text-base font-semibold">本日の利用者（{active.length}名）</h2>
              <Switch
                checked={showAbsent}
                onCheckedChange={setShowAbsent}
