              />
            </div>
            <ul className="grid grid-cols-1 gap-3 sm:grid-cols-2 xl:grid-cols-3">
              {users
                .filter((u) => showAbsent || u.status !== "欠席")
                .map((u) => (
                  <li key={u.id}>
                    <Card className={u.status === "欠席" ? "opacity-70" : undefined}>
                      <CardContent className="flex flex-col gap-3 p-4">
                        <UserCell u={u} onClick={() => setOpenId(u.id)} />
                        <Separator />
                        <div className="flex flex-wrap gap-1.5">
                          <CareChip label="入浴" state={u.bath} icon={<IconBath />} />
                          <CareChip label="食事" state={u.meal} icon={<IconToolsKitchen2 />} />
                          <CareChip label="訓練" state={u.exercise} icon={<IconCalendarStats />} />
                          <CareChip label="レク" state={u.rec} />
                          {hasAbnormalVital(u) ? (
                            <Badge variant="destructive" icon={<IconAlertTriangle />}>
                              バイタル要確認
                            </Badge>
                          ) : null}
                          {u.record.signed ? (
