                      ) : (
                        <EmptyState title="該当する利用者がいません" headingLevel={4} />
                      )}
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          </div>
        </TabsContent>

        {/* ─────────── 入浴・機能訓練の予定/実施（ScheduleGrid） ─────────── */}
        <TabsContent value="schedule">
          <ScheduleGrid
            label="本日の入浴・食事・機能訓練・レクの予定／実施"
            cornerLabel="利用者"
            minColumnWidth={104}
            rowHeaderWidth={132}
            rows={active.map((u) => ({
              id: u.id,
              label: u.name,
              sublabel: u.careLevel,
              ariaLabel: u.name,
            }))}
            columns={[
              { id: "bath", label: "入浴" },
              { id: "meal", label: "食事" },
              { id: "exercise", label: "機能訓練" },
              { id: "rec", label: "レク" },
            ]}
            cells={active.flatMap((u) => [
              careScheduleCell(u, "bath", u.bath),
              careScheduleCell(u, "meal", u.meal),
              careScheduleCell(u, "exercise", u.exercise),
              careScheduleCell(u, "rec", u.rec),
            ])}
          />
          <p className="mt-3 text-xs text-muted-foreground">
            実施＝緑／予定＝青／拒否＝赤。各セルは入浴・食事・機能訓練・レクの当日の状況です。
          </p>
        </TabsContent>

        {/* ─────────── 加算・担当 ─────────── */}
        <TabsContent value="additions">
          <div className="flex flex-col gap-6">
            <section className="flex flex-col gap-3">
              <h2 className="text-base font-semibold">本日の加算 算定状況</h2>
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                {additionMeta.map((a) => {
                  const count = additionCounts[a.id];
                  const target =
                    a.id === "bath" ? bathPlanned : active.length;
                  return (
                    <Card key={a.id}>
                      <CardContent className="flex flex-col gap-2 p-4">
                        <div className="flex items-center justify-between gap-2">
                          <span className="font-medium">{a.name}</span>
                          <Badge variant="outline">{a.unit}</Badge>
