                        <Meter
                          label={`算定対象 ${count}名 / ${target}名`}
                          value={count}
                          max={Math.max(target, 1)}
                          direction="fill-is-good"
                          formatValue={(n) => `${Math.round(n)}名`}
                        />
                      </CardContent>
                    </Card>
                  );
                })}
              </div>
            </section>

            <Separator />

            <section className="flex flex-col gap-3">
              <h2 className="text-base font-semibold">担当（利用者 ⟷ 担当職員）</h2>
              <ul className="flex flex-col gap-2">
                {active.map((u) => {
                  const s = staffById[u.primaryStaffId];
                  return (
                    <li key={u.id}>
                      <Card>
                        <CardContent className="p-3">
                          <RelationshipRow
                            size="sm"
                            from={{
                              name: u.name,
                              secondary: u.careLevel,
                              avatarClassName: u.avatarColor,
                            }}
                            to={{
                              name: s?.name ?? u.primaryStaffId,
                              secondary: s?.role,
                              avatarClassName: s?.avatarColor,
                            }}
                            relationshipLabel="担当"
                          />
                        </CardContent>
                      </Card>
                    </li>
                  );
                })}
              </ul>
            </section>
          </div>
        </TabsContent>
      </Tabs>

      {/* ─────────── 利用者 詳細 ドリルイン ─────────── */}
      <Sheet open={openId !== null} onOpenChange={(o) => !o && setOpenId(null)}>
        <SheetContent side="right" className="w-full overflow-y-auto sm:max-w-lg">
          {openUser ? (
            <UserDetail
              u={openUser}
              onSign={(v) => setRecordSigned(openUser.id, v)}
              onBathResult={(r) => setBathResult(openUser.id, r)}
            />
          ) : null}
        </SheetContent>
      </Sheet>
    </div>
  );
}

