        {u.bath === "拒否" ? (
          <div className="flex flex-col gap-2">
            <p className="text-xs font-medium text-muted-foreground">入浴拒否の判断 — 2人確認</p>
            <CoSign
              primaryId={currentStaffId}
              value={coSign}
              onSign={setCoSign}
              attestations={[{ id: "att-1", label: "入浴拒否の対応・声かけが適切であったことを確認" }]}
              signerLabel="確認者ID（フロアリーダー）"
            />
          </div>
        ) : null}
      </section>
    </div>
  );
}

function fmtNow(): string {
  const d = new Date();
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
}
